#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <limits.h>

bool is_valid_partition(int boards[], int n, int k, int max_length) {
    int painters_required = 1, current_length = 0;

    for (int i = 0; i < n; i++) {
        if (current_length + boards[i] > max_length) {
            painters_required++;
            current_length = boards[i];
            if (painters_required > k) {
                return false;
            }
        } else {
            current_length += boards[i];
        }
    }
    return true;
}

int painter_partition(int boards[], int n, int k) {
    int low = 0, high = 0, result = INT_MAX;

    // Calculate low (max element) and high (sum of all elements)
    for (int i = 0; i < n; i++) {
        if (boards[i] > low) {
            low = boards[i];
        }
        high += boards[i];
    }

    while (low <= high) {
        int mid = low + (high - low) / 2;

        if (is_valid_partition(boards, n, k, mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return result;
}

