function painterPartition(boards, k) {
    let low = Math.max(...boards);
    let high = boards.reduce((sum, length) => sum + length, 0);
    let result = high;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);

        if (isValidPartition(boards, k, mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return result;
}

